import{_ as e,o as t,c as r,a0 as d}from"./chunks/framework.RL10UjUE.js";const u=JSON.parse('{"title":"スマートビュー","description":"","frontmatter":{},"headers":[],"relativePath":"guide/smart-views.md","filePath":"guide/smart-views.md"}'),o={name:"guide/smart-views.md"};function i(h,a,l,s,n,c){return t(),r("div",null,[...a[0]||(a[0]=[d('<h1 id="スマートビュー" tabindex="-1">スマートビュー <a class="header-anchor" href="#スマートビュー" aria-label="Permalink to &quot;スマートビュー&quot;">​</a></h1><p>サイドバー上部のビュー切り替えで、ブックマークの表示をコンテキストに応じて変更できます。</p><h2 id="ビューの種類" tabindex="-1">ビューの種類 <a class="header-anchor" href="#ビューの種類" aria-label="Permalink to &quot;ビューの種類&quot;">​</a></h2><h3 id="すべて" tabindex="-1">すべて <a class="header-anchor" href="#すべて" aria-label="Permalink to &quot;すべて&quot;">​</a></h3><p>登録されているすべてのブックマークを表示します（デフォルト）。</p><h3 id="未分類" tabindex="-1">未分類 <a class="header-anchor" href="#未分類" aria-label="Permalink to &quot;未分類&quot;">​</a></h3><p>タグが一つも設定されていないブックマークのみを表示します。AI アシスタントで一括タグ付けするのに便利です。</p><h3 id="最近追加" tabindex="-1">最近追加 <a class="header-anchor" href="#最近追加" aria-label="Permalink to &quot;最近追加&quot;">​</a></h3><p>過去 7 日以内に追加されたブックマークを表示します。</p><h3 id="使われていない" tabindex="-1">使われていない <a class="header-anchor" href="#使われていない" aria-label="Permalink to &quot;使われていない&quot;">​</a></h3><p><code>visit_count = 0</code> のブックマークを表示します。ブックマークの整理に活用できます。</p><h3 id="よく見る" tabindex="-1">よく見る <a class="header-anchor" href="#よく見る" aria-label="Permalink to &quot;よく見る&quot;">​</a></h3><p>訪問回数が多いブックマークを降順に表示します。</p><h2 id="デバイススコープ" tabindex="-1">デバイススコープ <a class="header-anchor" href="#デバイススコープ" aria-label="Permalink to &quot;デバイススコープ&quot;">​</a></h2><p>サイドバー下部のスコープ切替で、表示範囲を制御できます。</p><table tabindex="0"><thead><tr><th>スコープ</th><th>表示内容</th></tr></thead><tbody><tr><td>すべて</td><td>全ブックマーク</td></tr><tr><td>共有のみ</td><td><code>device_scoped = false</code> のブックマークのみ</td></tr><tr><td>デバイス固有のみ</td><td><code>device_scoped = true</code> のブックマークのみ</td></tr></tbody></table><p>スコープはスマートビューと組み合わせて使えます。たとえば「デバイス固有のみ」＋「最近追加」で、今使っているデバイスで最近追加したブックマークだけを見ることができます。</p><h2 id="タグフィルタ" tabindex="-1">タグフィルタ <a class="header-anchor" href="#タグフィルタ" aria-label="Permalink to &quot;タグフィルタ&quot;">​</a></h2><p>サイドバーのタグ一覧からタグをクリックすると、そのタグが付いたブックマークのみに絞り込みができます。スマートビュー・スコープと同時に適用可能です。</p>',19)])])}const _=e(o,[["render",i]]);export{u as __pageData,_ as default};
